import React from 'react';

import './hero.scss';
import { strings } from '../../util';
import { fb, ig, linkedin, github } from '../../assets/icons';

const Hero = () => {
    const data = [
        {
            link: strings.fb,
            src: fb,
        },
        {
            link: strings.ig,
            src: ig,
        },
        {
            link: strings.github,
            src: github,
        },
        {
            link: strings.linkedin,
            src: linkedin,
        },
    ];

    return (
        <section>
            <div className='hero'>
                <img src={strings.photoUrl} alt={strings.name} />
                <div className='hero_content'>
                    <p>{strings.name}</p>
                    <span>
                        <strong>{strings.role}</strong> <br></br>{' '}
                        <strong>{strings.company}</strong>
                    </span>
                    <ul>
                        {data.map((item, index) => (
                            <li key={index}>
                                <a href={item.link}>
                                    <img src={item.src} alt='link' />
                                </a>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </section>
    );
};

export default Hero;
